import{_ as o,C as i,o as n,c,j as e,a as d,E as r,ag as s}from"./chunks/framework.HG0H2VLS.js";const x=JSON.parse('{"title":"IconNavigation","description":"","frontmatter":{},"headers":[],"relativePath":"cc-patterns/icon-navigation.md","filePath":"cc-patterns/icon-navigation.md"}'),l={name:"cc-patterns/icon-navigation.md"};function h(p,t,g,m,b,u){const a=i("ComponentDemo");return n(),c("div",null,[t[0]||(t[0]=e("hr",null,null,-1)),t[1]||(t[1]=e("h2",{id:"title-iconnavigation",tabindex:"-1"},[d("title: IconNavigation "),e("a",{class:"header-anchor",href:"#title-iconnavigation","aria-label":'Permalink to "title: IconNavigation"'},"​")],-1)),t[2]||(t[2]=e("h1",{id:"iconnavigation",tabindex:"-1"},[d("IconNavigation "),e("a",{class:"header-anchor",href:"#iconnavigation","aria-label":'Permalink to "IconNavigation"'},"​")],-1)),r(a,{src:"/demos/src/cc/patterns/IconNavigation/IconNavigation.html"}),t[3]||(t[3]=s('<h2 id="variant-×-state-matrix" tabindex="-1">Variant × State Matrix <a class="header-anchor" href="#variant-×-state-matrix" aria-label="Permalink to &quot;Variant × State Matrix&quot;">​</a></h2><p>Single variant — <code>Tier=Pattern</code>. No Selected / Hover / Active variants exist in the component set. Per user direction: items render as <code>&lt;a&gt;</code> links with a CSS-only hover (glyph + label darken to <code>--ai-text-primary</code>). No current-page/active state is implemented because Figma defines none.</p><table tabindex="0"><thead><tr><th>Item</th><th>Icon node</th><th>Glyph (intrinsic px)</th><th>Label</th></tr></thead><tbody><tr><td>Publish</td><td>4218:4268</td><td>45.663 × 41 → 46 × 41</td><td>Publish</td></tr><tr><td>Promote</td><td>4218:4278</td><td>49 × 41.094 → 49 × 41</td><td>Promote</td></tr><tr><td>Social</td><td>4218:4328</td><td>36.5 × 39 → 37 × 39</td><td>Social</td></tr><tr><td>Media</td><td>4218:4288</td><td>52 × 38 → 52 × 38</td><td>Media</td></tr><tr><td>Structure</td><td>4218:4295</td><td>49.25 × 36.76 → 49 × 37</td><td>Structure</td></tr><tr><td>Design</td><td>4218:4299</td><td>52 × 47.719 → 52 × 48</td><td>Design</td></tr><tr><td>Commerce</td><td>4218:4318</td><td>47.5 × 43.438 → 48 × 43</td><td>Commerce</td></tr><tr><td>Analyse</td><td>4218:4313</td><td>52 × 41 → 52 × 41</td><td>Analyse</td></tr><tr><td>Settings</td><td>4218:4285</td><td>44 × 44 → 44 × 44</td><td>Settings</td></tr></tbody></table><p>Glyph dimensions are brand-asset intrinsic sizes (allowed raw-px exception — asset metadata, not spacing tokens). Rounded to whole px; exact Figma values noted above.</p><h2 id="icon-assets" tabindex="-1">Icon assets <a class="header-anchor" href="#icon-assets" aria-label="Permalink to &quot;Icon assets&quot;">​</a></h2><p>The nine glyphs are the <strong>exact Figma SVGs</strong> exported to <code>img/cc-nav/&lt;name&gt;.svg</code>. They are stroke-based line art (<code>stroke-width: 1.5</code>). Rendered via CSS <code>mask</code> painted in <code>--ai-text-secondary</code> — the same brand-asset convention used for <code>affinoMark.svg</code> / <code>affinoLogo.svg</code> in <code>Sidebar.css</code> / <code>Menu.css</code>. This keeps the glyphs theme-aware (CC light/dark) rather than baking the stroke colour into the file. The SVGs are <strong>not</strong> Lucide icons (they are bespoke Affino module glyphs), so the Lucide rule does not apply.</p><h2 id="css-classes" tabindex="-1">CSS Classes <a class="header-anchor" href="#css-classes" aria-label="Permalink to &quot;CSS Classes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma</th><th>CSS</th></tr></thead><tbody><tr><td>IconNavigation (4218:4680) — full-width strip</td><td><code>.cc-icon-nav</code></td></tr><tr><td>Inner 768 row (4218:4466)</td><td><code>.cc-icon-nav__list</code></td></tr><tr><td>Item column (e.g. 4218:4457)</td><td><code>.cc-icon-nav__item</code> &gt; <code>.cc-icon-nav__link</code></td></tr><tr><td>Icon slot h-48 (e.g. 4218:4470)</td><td><code>.cc-icon-nav__icon-box</code></td></tr><tr><td>Glyph img (e.g. 4218:4268)</td><td><code>.cc-icon-nav__icon--&lt;name&gt;</code></td></tr><tr><td>Label <code>&lt;p&gt;</code> (e.g. 4218:4260)</td><td><code>.cc-icon-nav__label</code></td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma variable</th><th>CSS token</th><th>Role</th></tr></thead><tbody><tr><td><code>--ai-surface-minimal</code> (Figma bind)</td><td><code>--cc-actions-menu-secondary-bg</code></td><td>Strip background — <strong>user override</strong> (#e7edf0 light / #1e293b dark) to pair with the CC ActionsMenu, instead of the Figma-bound <code>--ai-surface-minimal</code></td></tr><tr><td><code>--ai-spacing-4</code> (12)</td><td><code>--ai-spacing-4</code></td><td>Strip vertical padding</td></tr><tr><td><code>--ai-size-11</code> (768)</td><td><code>--ai-size-11</code></td><td>Row max-width</td></tr><tr><td><code>--ai-spacing-7</code> (32)</td><td><code>--ai-spacing-7</code></td><td>Row horizontal padding + item gap</td></tr><tr><td><code>--ai-spacing-9</code> (48)</td><td><code>--ai-spacing-9</code></td><td>Icon-box height</td></tr><tr><td><code>--ai-spacing-3</code> (8)</td><td><code>--ai-spacing-3</code></td><td>Icon→label gap</td></tr><tr><td><code>--ai-text-secondary</code> (#335562 CC)</td><td><code>--ai-text-secondary</code></td><td>Glyph paint + label colour (rest)</td></tr><tr><td><code>--ai-text-primary</code> (#00222f CC)</td><td><code>--ai-text-primary</code></td><td>Glyph + label on hover</td></tr><tr><td><code>--ai-font-title</code> (Inter)</td><td><code>--ai-font-title</code></td><td>Label family</td></tr><tr><td><code>--ai-font-medium</code></td><td><code>--ai-font-medium</code></td><td>Label weight</td></tr><tr><td><code>--ai-font-fixed-xxs</code> (12)</td><td><code>--ai-font-fixed-xxs</code></td><td>Label size</td></tr></tbody></table><p>Label <code>letter-spacing: 0.36px</code> and <code>line-height: 1.4</code> — optical typographic values (letter-spacing is an allowed raw-px exception; 1.4 is unitless).</p><h2 id="token-gaps" tabindex="-1">Token Gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token Gaps&quot;">​</a></h2><p>None. Every design value maps to an existing <code>--ai-*</code> token; glyph dimensions are the documented brand-asset exception.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>CC brand context: requires <code>data-brand=&quot;cc&quot;</code> on an ancestor so the <code>--ai-*</code> tokens resolve to their CC values (<code>tokens-cc.css</code> / <code>tokens-cc-dark.css</code>).</li><li>No Device=Mobile variant and no &quot;mobile&quot; mode referenced in the design context — the row caps at 768 and compresses on narrower viewports; no responsive variant was invented.</li><li><code>mask</code> alpha source: the SVG strokes are opaque so the line art becomes the mask shape; <code>mask-size: 100% 100%</code> against the per-glyph box reproduces the Figma proportions.</li></ul>',15))])}const k=o(l,[["render",h]]);export{x as __pageData,k as default};
